import os
import shutil

def delete_uploaded_file(filename):
    # Get the absolute path of the uploads directory
    uploads_dir = os.path.abspath('uploads')
    
    # Get the absolute path of the file to be deleted
    file_path = os.path.abspath(os.path.join(uploads_dir, filename))
    
    # Ensure the file path is within the uploads directory
    if not file_path.startswith(uploads_dir):
        raise ValueError("Invalid file path: file must be within uploads directory")
    
    # Check if file exists
    if os.path.exists(file_path):
        # Check if it's actually a file (not a directory)
        if os.path.isfile(file_path):
            os.remove(file_path)
            return True
        else:
            raise ValueError("Path is not a file")
    else:
        raise FileNotFoundError("File not found")